def generate_html(data, image_paths):
    # HTML模板
    html_template = f'''
    <!DOCTYPE html>
    <html lang="zh-CN">
    <head>
        <meta charset="UTF-8">
        <title>{data['main_title']}</title>
        <style>
            body {{ 
                max-width: 800px;
                margin: 20px auto;
                padding: 0 20px;
                line-height: 1.6;
                font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
            }}
            .meta-info {{ 
                color: #666;
                border-bottom: 1px solid #eee;
                padding-bottom: 10px;
                margin-bottom: 20px;
            }}
            img {{ 
                max-width: 100%;
                height: auto;
                margin: 15px 0;
                border: 1px solid #ddd;
                border-radius: 4px;
                padding: 5px;
            }}
            h1 {{ color: #222; }}
            p {{ margin: 1em 0; }}
        </style>
    </head>
    <body>
        <h1>{data['main_title']}</h1>
        <div class="meta-info">
            <p>作者：{data['author']}</p>
            <p>发布时间：{data['publish_time']}</p>
        </div>
        {generate_content_html(data['content'], image_paths)}
    </body>
    </html>
    '''
    return html_template

def generate_content_html(content_data, image_paths):
    html_parts = []
    img_index = 0

    for item_type, content in content_data:
        if item_type == 'text':
            # 保留换行符转换
            paragraphs = content.split('\n')
            html_parts.extend([f'<p>{p}</p>' for p in paragraphs if p.strip()])
        elif item_type == 'image':
            img_index += 1
            img_path = image_paths[img_index-1]
            if img_path and os.path.exists(img_path):
                html_parts.append(f'<img src="{img_path}" alt="图片{img_index}">')
            else:
                html_parts.append(f'<div style="color:red">[图片{img_index}下载失败]</div>')

    return '\n'.join(html_parts)

def save_as_html(data, image_paths, filename='article.html'):
    html_content = generate_html(data, image_paths)

    with open(filename, 'w', encoding='utf-8') as f:
        f.write(html_content)

    # 验证文件完整性
    with open(filename, 'r', encoding='utf-8') as f:
        content = f.read()
        if data['main_title'] not in content:
            raise Exception("HTML生成异常，标题丢失")

    print(f"已生成自包含HTML文件：{os.path.abspath(filename)}")

